// ❌ BAD - no CorrelationId set, sender cannot match the reply
var request = new ServiceBusMessage(Encoding.UTF8.GetBytes(payload));
request.ReplyTo = "orders-reply";
await sender.SendMessageAsync(request);

// ✅ GOOD - deterministic CorrelationId ties reply to request
var correlationId = Guid.NewGuid().ToString();
var request = new ServiceBusMessage(Encoding.UTF8.GetBytes(payload))
{
    ReplyTo = "orders-reply",
    CorrelationId = correlationId,
    TimeToLive = TimeSpan.FromSeconds(30)
};
await sender.SendMessageAsync(request);
// sender polls orders-reply filtering on CorrelationId

// ❌ BAD - direct method calls couple the order service to every downstream system
await emailService.SendOrderConfirmation(order);
await inventoryService.ReserveStock(order);
await loyaltyService.AwardPoints(order);

// ✅ GOOD - publish once, each subscriber reacts independently
var message = new ServiceBusMessage(
    BinaryData.FromObjectAsJson(order))
{
    Subject = "OrderPlaced"
};
await topicSender.SendMessageAsync(message);
// email, inventory, loyalty each have their own subscription

// ❌ BAD - sequential processing, total time = sum of all items
foreach (var productId in productIds)
    await context.CallActivityAsync("ResizeImage", productId);

// ✅ GOOD - fan-out: all items run in parallel, time = slowest item
var tasks = productIds
    .Select(id => context.CallActivityAsync<string>("ResizeImage", id))
    .ToList();
var results = await Task.WhenAll(tasks);
// fan-in: results now contains output from all parallel branches

// ❌ BAD - direct HTTP call, a spike of 10K orders/second overwhelms the inventory service
await inventoryHttpClient.PostAsJsonAsync("/reserve", order);

// ✅ GOOD - drop order on the queue; inventory service consumes at its own pace
var message = new ServiceBusMessage(
    BinaryData.FromObjectAsJson(order));
await orderQueueSender.SendMessageAsync(message);
// autoscaler watches queue depth and adds consumer instances when backlog grows

// ❌ BAD - immediate retry in a tight loop hammers the service and risks duplicates
for (int i = 0; i < 5; i++)
    await paymentGateway.ChargeCustomerAsync(order);

// ✅ GOOD - Polly: exponential back-off + jitter, only for transient HTTP errors
var retryPolicy = Policy
    .Handle<HttpRequestException>()
    .OrResult<HttpResponseMessage>(r => (int)r.StatusCode >= 500)
    .WaitAndRetryAsync(3,
        attempt => TimeSpan.FromSeconds(Math.Pow(2, attempt))
                   + TimeSpan.FromMilliseconds(new Random().Next(0, 200)));
await retryPolicy.ExecuteAsync(() =>
    inventoryHttpClient.PostAsJsonAsync("/reserve", order));

// ❌ BAD - no circuit breaker; 30-second timeouts exhaust all threads during an outage
var result = await paymentGateway.ChargeAsync(order);

// ✅ GOOD - circuit breaker opens after 3 failures, half-opens after 15 seconds
var circuitBreaker = Policy
    .Handle<HttpRequestException>()
    .CircuitBreakerAsync(
        exceptionsAllowedBeforeBreaking: 3,
        durationOfBreak: TimeSpan.FromSeconds(15),
        onBreak: (ex, duration) => log.Warning("Payment gateway circuit open"),
        onReset: () => log.Information("Payment gateway circuit closed"));
await circuitBreaker.ExecuteAsync(() =>
    paymentGateway.ChargeAsync(order));

// ❌ BAD - shared HttpClient with no concurrency limit; a slow payment gateway
// exhausts all threads and blocks product search calls too
var result = await sharedHttpClient.GetAsync("/inventory/check");

// ✅ GOOD - each dependency gets its own bulkhead
var paymentBulkhead = Policy.BulkheadAsync(
    maxParallelization: 20,
    maxQueuingActions: 10);
var inventoryBulkhead = Policy.BulkheadAsync(
    maxParallelization: 20,
    maxQueuingActions: 10);
// slow payment gateway only blocks its own 20 threads

// ❌ BAD - 2PC across services; fragile and most services do not support it
using var tx = new TransactionScope(TransactionScopeAsyncFlowOption.Enabled);
await inventoryService.ReserveAsync(order);
await paymentService.ChargeAsync(order);
tx.Complete(); // distributed lock across two services

// ✅ GOOD - orchestrated saga with compensation on failure
var reservationId = await context.CallActivityAsync<string>("ReserveInventory", order);
try {
    await context.CallActivityAsync("ChargePayment", order);
} catch {
    await context.CallActivityAsync("ReleaseReservation", reservationId);
    throw;
}

// ❌ BAD - same Order entity used for both complex writes and read projections
public class OrderController {
    public async Task<Order> GetOrder(Guid id) =>
        await db.Orders.Include(o => o.Lines).FirstAsync(o => o.Id == id);
    public async Task CreateOrder(Order order) { db.Orders.Add(order); }
}

// ✅ GOOD - separate read model (fast projection) and write model (business rules)
public class OrderQueryHandler {
    public Task<OrderSummaryDto> Handle(GetOrderSummaryQuery q) =>
        readDb.OrderSummaries.FindAsync(q.OrderId); // pre-joined, denormalized
}
public class PlaceOrderHandler {
    public async Task Handle(PlaceOrderCommand cmd) {
        var order = Order.Place(cmd); // business rules enforced
        await writeDb.Orders.AddAsync(order);
    }
}

// ❌ BAD - INSERT without checking; duplicate message creates duplicate loyalty points
await db.ExecuteAsync(
    "INSERT INTO LoyaltyPoints (OrderId, Points) VALUES (@id, @pts)",
    new { id = order.Id, pts = 100 });

// ✅ GOOD - idempotent upsert; safe to run multiple times
await db.ExecuteAsync(@"
    INSERT INTO LoyaltyPoints (OrderId, Points)
    VALUES (@id, @pts)
    ON CONFLICT (OrderId) DO NOTHING",
    new { id = order.Id, pts = 100 });
// OrderId is the natural idempotency key - second run is a no-op

// ❌ BAD - no correlation ID; logs from five services cannot be linked
logger.LogInformation("Order placed for customer {CustomerId}", order.CustomerId);
await inventoryHttpClient.PostAsJsonAsync("/reserve", order);

// ✅ GOOD - propagate correlation ID on every outbound call and log entry
var correlationId = HttpContext.TraceIdentifier;
using (logger.BeginScope(new { CorrelationId = correlationId })) {
    logger.LogInformation("Order placed for customer {CustomerId}", order.CustomerId);
    inventoryHttpClient.DefaultRequestHeaders.Add("X-Correlation-ID", correlationId);
    await inventoryHttpClient.PostAsJsonAsync("/reserve", order);
}

// ❌ BAD - DB write and message publish are not atomic; crash between them loses the event
await db.Orders.AddAsync(order);
await db.SaveChangesAsync();
await serviceBusSender.SendMessageAsync(new ServiceBusMessage(orderJson));

// ✅ GOOD - Outbox pattern: both writes in one DB transaction; relay publishes the event
await db.Orders.AddAsync(order);
db.OutboxMessages.Add(new OutboxMessage {
    Type = "OrderPlaced",
    Payload = JsonSerializer.Serialize(order),
    CreatedAt = DateTime.UtcNow
});
await db.SaveChangesAsync();
// background relay reads OutboxMessages and publishes to Service Bus

// ❌ BAD - random MessageId on each send; broker duplicate detection is useless on retry
var msg = new ServiceBusMessage(BinaryData.FromObjectAsJson(payment))
{
    MessageId = Guid.NewGuid().ToString()
};

// ✅ GOOD - deterministic MessageId so the broker can deduplicate producer retries
var msg = new ServiceBusMessage(BinaryData.FromObjectAsJson(payment))
{
    MessageId = $"payment-{payment.OrderId}-{payment.AttemptNumber}"
};
await sender.SendMessageAsync(msg);
// consumer also uses ON CONFLICT DO NOTHING as a second layer

// ❌ BAD - no SessionId; competing consumers process events out of order
var msg = new ServiceBusMessage(BinaryData.FromObjectAsJson(orderEvent));
await sender.SendMessageAsync(msg);

// ✅ GOOD - SessionId = orderId; all events for one order go to one consumer in order
var msg = new ServiceBusMessage(BinaryData.FromObjectAsJson(orderEvent))
{
    SessionId = orderEvent.OrderId.ToString()
};
await sender.SendMessageAsync(msg);
// consumer processes OrderPlaced then OrderPaid then OrderShipped in strict FIFO per order
